-- Enrichment marathon batch: Mindustry, Miniflux, MinIO, MintHCM, Mintlify, Minus Games, Miro, MiroTalk

-- ── Mindustry ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mindustry is a free, open-source hybrid tower-defense and factory-automation game where players build resource-processing chains to arm defenses and conquer enemy bases.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free (paid copies available on Steam and app stores)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mindustry Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mindustry is a free open-source tower-defense and factory-building game. See features, platforms, pricing and how it compares to Factorio and similar games.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mindustry is a free and open-source real-time strategy game that blends tower defense with factory-style resource automation, created by a solo developer known by the pseudonym Anuke (real name reported as Anton Kramskoi, also credited under the handle Anuken). The project began in April 2017 as an entry for the itch.io 'Metal Monstrosity' game jam, where it placed first among 15 submissions. Its first public release (v1) shipped in 2017, and the game arrived on Steam with v3 in 2019. Mindustry is licensed under the GNU General Public License v3 (GPLv3), with its full source code hosted on GitHub under the Anuken/Mindustry repository, making it one of the more prominent fully open-source commercial-quality games. It is written primarily in Java using the libGDX framework, which allows it to run across Windows, macOS, Linux, Android, and iOS. Because it is open source, players can freely mod the game, inspect its code, and compile it themselves; the official builds are distributed free of charge from the developer's itch.io page and GitHub releases, while paid copies (identical in functionality) are sold on Steam and mobile app stores primarily to support development, since the game has no advertisements or in-app purchases. Core gameplay involves mining and transporting resources such as copper, lead, and titanium via conveyor belts, building factories that refine raw materials into components and ammunition, and constructing turrets and walls to repel waves of enemy forces, echoing mechanics popularized by Factorio combined with classic tower defense. Major updates have substantially expanded the game over time: version 6 (2020) introduced full real-time-strategy elements including unit commands and control groups, described by the community as a complete overhaul, while version 7 (2022) added a second planet, Erekir, along with new unit types and individually selectable RTS unit control. The game supports both single-player campaigns and multiplayer servers, including community-hosted and competitive PvP servers, and has an active modding community that produces custom maps, mods, and total conversions. Because there is no company behind Mindustry, there is no traditional pricing model, funding history, headquarters, or employee count; development is instead funded through voluntary donations, Patreon-style support, and optional paid Steam/app-store purchases. Its target audience is fans of automation and simulation games (Factorio, Satisfactory) who also enjoy tower-defense strategy, as well as players who value open-source, ad-free, DRM-free software. Its main points of differentiation from paid competitors like Factorio are its complete lack of monetization pressure, full source availability, cross-platform mobile support, and its GPL-licensed community-driven development model, which is unusual for a game of its scope and polish.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9a0efe36-6967-41a8-8703-57fdd1450a58';

