-- ── Miniflux ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Miniflux is a minimalist, self-hosted, open-source RSS and Atom feed reader built in Go with a focus on privacy, speed, and simplicity.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium (free self-hosted, optional paid hosted plan)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); $15/year hosted$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Miniflux Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Miniflux is a minimalist, self-hosted RSS reader written in Go. Read about its features, self-hosting requirements, $15/year hosted plan, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Miniflux is a minimalist, opinionated, open-source RSS and Atom feed reader created by French developer Frederic Guillot. It is distributed under the permissive Apache 2.0 license, with its full source code (the current 'v2' rewrite) hosted publicly on GitHub under the miniflux organization. The application is written in Go and compiles to a single static binary with no external runtime dependencies other than a PostgreSQL database, which is the only supported data store. This architecture makes Miniflux extremely lightweight: a self-hosted instance can run comfortably on a low-cost VPS with roughly 1 vCPU and 1GB of RAM, often idling at around 20MB of RAM usage, and can be deployed via Docker, prebuilt binaries, or Debian/RPM packages. Miniflux has no dedicated company, VC funding, or headquarters behind it; it is maintained as an independent open-source project, and there is no publicly disclosed founding date for the project as a formal product beyond its GitHub commit history stretching back to the early-to-mid 2010s. Its design philosophy deliberately rejects feature bloat: the interface has no images loaded by default (for speed and privacy), no third-party trackers, no telemetry, and strips tracking parameters from article URLs. Core functionality includes fetching full article content from feeds that only publish summaries, keyboard-driven navigation, a clean reading view, support for external integrations (read-later services like Pocket, Wallabag, and Instapaper; notification services), OPML import/export, and a full REST API used by numerous third-party mobile and desktop client apps (since Miniflux itself ships only a web interface). Pricing is twofold: the software itself is completely free and open source for anyone to self-host, requiring only server costs (commonly cited as low as $5-10/month on a small VPS); alternatively, the maintainer offers an official hosted version at reader.miniflux.app for $15/year, which includes a 15-day free trial and removes the need to manage a server. This makes Miniflux dramatically cheaper than commercial hosted RSS readers such as Feedly or Inoreader, which typically charge $6-12/month for comparable premium tiers. Miniflux's target audience is developers, privacy-conscious power users, and technically capable individuals who want a fast, no-frills, self-hostable RSS reader rather than a feature-rich but heavier consumer product. Its main competitors include FreshRSS, Tiny Tiny RSS, NewsBlur, Feedly, and Inoreader; Miniflux differentiates itself through its extreme minimalism, single-binary Go implementation, strict privacy stance, and low resource footprint compared to PHP- or JavaScript-heavy alternatives like FreshRSS or Tiny Tiny RSS.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '126ce4f2-e1c8-43fc-b77f-37c96ff7806a';

