-- ── MintHCM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MintHCM is a free, open-source Human Capital Management (HCM) platform forked from SuiteCRM, covering recruitment, onboarding, performance, and workforce management.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (free) with paid implementation/support services$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Polish$q$, $q$Czech$q$]::text[],
  seo_title = COALESCE($q$MintHCM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MintHCM is a free, open-source HR and HCM platform built on SuiteCRM. Explore its recruitment, onboarding, and performance features plus pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MintHCM is an open-source Human Capital Management (HCM) platform designed to manage the full employee lifecycle, including recruitment, employer branding, onboarding, employee profiles, skills tracking, performance evaluation, time and leave management, and offboarding. It is architecturally a fork of SuiteCRM (itself derived from SugarCRM Community Edition), repurposed and substantially reworked from a sales-CRM codebase into an HR-focused system, meaning its underlying API and data model share strong similarities with SuiteCRM. MintHCM officially launched in May 2018, with its first public open-source release following in 2019; the Poland-based IT consultancy eVolpe has partnered with the project since that first public release and provides commercial implementation, customization, and support services through minthcm.com, while the core software itself remains free. The project is licensed as fully open source (AGPL v3, per its own positioning as having 'no gated features'), meaning organizations can download, self-host, and modify the platform at no licensing cost, paying only for their own server infrastructure or for optional professional services. As of recent tracking, the project has accumulated tens of thousands of downloads and several hundred GitHub stars, with community support available via forums, Discord, and documentation wikis rather than a traditional enterprise support contract structure (though paid support is available through eVolpe and partners). MintHCM has been translated into multiple languages, including Polish and Czech, reflecting its origins and core community base in Central/Eastern Europe. More recently, MintHCM has repositioned itself around AI-driven HR workflows, describing itself as an 'AI-enabled open source HCM' with native support for MCP (Model Context Protocol) and A2A (agent-to-agent) architectures, positioning the platform for organizations wanting to build AI agents on top of their HR data without vendor lock-in, and emphasizing full ownership of data, code, and infrastructure with deployment options on-prem, in the cloud, hybrid, or at the edge. A notable functional limitation is that MintHCM does not include payroll processing, which must be handled via separate integrated systems. Its target audience includes small and mid-sized organizations, staffing agencies, and HR teams seeking a fully open-source, self-hostable, and customizable HR platform as an alternative to closed-source SaaS HR systems like BambooHR, Workday, or Rippling. MintHCM's key differentiators are its zero-licensing-cost open-source model, deep customizability inherited from its SuiteCRM/SugarCRM lineage, full data ownership, and its more recent focus on AI-agent-native HR tooling.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6fd92840-a8d9-4354-97b1-b102f54b88d6';

