-- ── Mintlify ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mintlify is a modern documentation platform that helps developer teams build, host, and maintain API references and product docs, used by companies like Anthropic and Cursor.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$~50-100 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mintlify Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mintlify is a developer documentation platform backed by a16z. Compare its Starter, Pro, and Enterprise pricing, features, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mintlify is a documentation platform built to help developer-facing companies create, host, and maintain API references and product documentation. It was founded in 2022 by Han Wang and Hahnbee Lee, who met at Cornell University and built the company around the shared frustration of writing and maintaining software documentation. Mintlify is headquartered in San Francisco and has raised approximately $21 million in total funding: a $2.8 million seed round in May 2022 led by Bain Capital Ventures (with participation from TwentyTwo Ventures and Sourcegraph co-founder Quinn Slack), followed by an $18 million Series A in September 2024 led by Andreessen Horowitz (a16z), with participation from Bain Capital Ventures, Y Combinator, and TwentyTwo Ventures. As of the Series A announcement, Mintlify powered documentation for thousands of companies, including notable AI and developer-tool companies such as Anthropic, Perplexity, and Cursor, and reported reaching over 20 million developers annually. Functionally, Mintlify lets teams write documentation in Markdown/MDX, then automatically generates a fast, searchable, SEO-friendly documentation website with built-in components, API playgrounds, and versioning. The platform has increasingly incorporated AI features, including an AI-powered writing assistant, automated content generation from OpenAPI specs and codebases, and an in-docs AI chat 'Assistant' that answers user questions directly from the documentation content, plus AI 'Agent' and 'Automations' capabilities for keeping docs in sync with product and code changes. It also exposes documentation as an MCP (Model Context Protocol) server, letting AI coding assistants and agents query docs programmatically. Pricing follows a three-tier freemium model: a free Starter plan for individuals and small teams offering full platform access, a custom domain, a web editor, authentication, an MCP server, an API playground, and 10,000 usage credits per month (with $0.01 per overage credit); a paid Pro plan for startups and growing teams that adds the AI Agent, Assistant, Automations, preview deployments, admin APIs, and advanced insights, with custom credit volumes and discounts; and a custom-priced Enterprise plan for larger organizations that adds SSO, SCIM, RBAC, a performance SLA, enterprise security and legal terms, self-hosting options, migration support, and 24/7 incident monitoring. Mintlify's target audience is developer-tool and API-first companies — from early-stage startups to large enterprises and AI labs — that need polished, maintainable documentation without building custom tooling in-house. Its main competitors include GitBook, ReadMe, Docusaurus (self-hosted/open source), and Stripe-style custom docs stacks; Mintlify differentiates itself through its design-forward output, deep AI integration (writing assistance, in-docs chat, MCP server exposure), and strong adoption among prominent AI and developer-tool companies.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f62cd71f-7351-4b7b-9348-da3ff16476e0';

