-- ── Minus Games ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Minus Games is a small open-source suite of applications for distributing, running, and syncing PC games and save files from a self-hosted home server to client devices.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Minus Games Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Minus Games is an open-source home-server game and save-file distribution suite. Learn how it works, its features, and free self-hosted pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Minus Games is a niche, open-source software suite for distributing PC games and their save files from a self-hosted server to client machines, aimed primarily at home-server and homelab users who want to manage a personal game library outside of commercial storefronts like Steam. The project is maintained on GitHub under the account Accessory (repository Accessory/minus_games), and its documentation is published as a user guide at accessory.github.io/minus_games_user_guide. Public information about the project's founding date, creator identity, company affiliation, and funding is minimal or unavailable, consistent with its status as a small, community-maintained open-source tool rather than a commercial product. The suite consists of five separate applications: a Minus Games Server that hosts the game library, a Minus Games Client and a GUI client that download, install, and launch games on end-user machines, a Minus Games Finder that scans a designated folder on the server to detect installed games (with support for common engines such as Unity), and a Minus Games Updater that keeps game installations current with the latest files from the server. A key differentiating feature is save-file synchronization: in addition to keeping game installation files current across devices, Minus Games also syncs save files, allowing a player to start a session on one machine and continue seamlessly on another. The typical setup workflow involves configuring the server, placing game files in a designated directory, triggering a scan via the finder's REST endpoint, and then allowing client devices to browse, download, and launch games from that server. The project is distributed for free as open-source software, with no commercial pricing tiers; it is also packaged for Linux via Flathub for easier installation of the GUI client. Because of its narrow scope and small community, Minus Games has limited public documentation of company-style details (headquarters, employee count, funding), and users should expect it to function more like a personal/hobbyist infrastructure tool than a polished commercial product. Its target audience is technically inclined home-server operators and PC gamers with a library of non-Steam or DRM-free games who want Steam-like remote installation and save synchronization across their own devices. Comparable tools in this space include Playnite, Lutris, Heroic Games Launcher, and GameLauncher, though Minus Games' specific focus on a client-server home-network architecture with save-sync sets it apart from library aggregators that primarily unify existing storefronts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
