-- ── MiroTalk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MiroTalk is a self-hosted, open-source suite of WebRTC video-calling platforms (P2P, SFU, and more) built by independent developer Miroslav Pejic, unrelated to the Miro whiteboard company.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (free) with optional commercial licenses and paid support$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 130+ other languages via built-in localization$q$]::text[],
  seo_title = COALESCE($q$MiroTalk Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MiroTalk is an open-source, self-hosted WebRTC video calling platform with P2P and SFU editions. See features, AGPLv3 pricing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MiroTalk is a family of self-hosted, open-source WebRTC video-communication platforms created and maintained by independent developer Miroslav Pejic (GitHub handle miroslavpejic85). It is important to note that MiroTalk is entirely unrelated to Miro, the venture-backed online whiteboard company headquartered in Amsterdam and San Francisco — the similar naming is coincidental, and MiroTalk has no corporate, ownership, or investment ties to Miro. MiroTalk's codebase is released under the GNU Affero General Public License v3.0 (AGPLv3), meaning it is free to self-host and modify, with the requirement that modifications distributed to others remain open source under the same license. The project consists of several distinct sub-products, each maintained as a separate GitHub repository: MiroTalk P2P (peer-to-peer architecture for fast, direct browser-to-browser calls, hosted publicly as a live demo at p2p.mirotalk.com), MiroTalk SFU (a Selective Forwarding Unit architecture built with mediasoup, positioned as a self-hosted alternative to Zoom for larger group calls, demoed at sfu.mirotalk.com), MiroTalk C2C (a simplified one-to-one cam-to-cam calling variant limited to two participants per room for maximum privacy), MiroTalk BRO (a live broadcasting variant for streaming to unlimited viewers), and MiroTalk WEB (a room scheduling and management dashboard). The flagship MiroTalk P2P repository has accumulated around 4,600+ GitHub stars and roughly 750 forks, with an active Discord community and thousands of commits, indicating a moderately popular niche open-source project rather than a large company. Technically, the platforms are built primarily in JavaScript/Node.js with HTML and CSS, deployable via a small number of Docker Compose or npm commands, and can run on personal servers, VPS instances, or cloud infrastructure. Feature-wise, MiroTalk supports video calls up to 8K resolution at 60fps, screen sharing, session recording, markdown-enabled chat, a collaborative whiteboard, file sharing, OIDC-based authentication, JWT credentials, host protection and room passwords, a full REST API, embeddable iframe widgets, and localization into over 130 languages. There is no dedicated company behind MiroTalk, no formal funding rounds, headquarters, or employee count; the project instead sustains itself through GitHub Sponsors, corporate sponsorships listed on its repositories, and the sale of optional commercial/extended licenses through the developer's CodeCanyon marketplace listing for organizations that want additional customization rights or support beyond the free AGPLv3 terms. Its target audience is developers, startups, and privacy-conscious organizations that want to self-host video conferencing rather than depend on third-party cloud video platforms, avoiding recurring per-seat SaaS fees and retaining full control over call data. Its main competitors and comparison points include Jitsi Meet (also open source and self-hostable), BigBlueButton, Zoom, and Google Meet; MiroTalk differentiates itself through its lightweight self-hosting footprint, multiple architecture options (P2P vs. SFU) for different scale needs, and a permissive-to-use-but-copyleft AGPLv3 license that keeps the core product free.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f5b98a61-eacf-4efe-aaf6-07eff41492b5';

